  /** The writ type name. */
  name: string;
  /** Human-readable description, or null if none was provided. */
  description: string | null;
  /** Origin of this type: "builtin", "guild", or the contributing plugin id. */
  source: string;
  /** Whether this is the guild's default writ type. */
  isDefault: boolean;
}
```

