}
db.prepare('UPDATE books_spider_rigs SET content=? WHERE id=?').run(JSON.stringify(r), 'rig-mnrpc8xr-3234956c');
const after = JSON.parse(db.prepare('SELECT content FROM books_spider_rigs WHERE id=?').get('rig-mnrpc8xr-3234956c').content);
